# Generated by google (gemini-2.5-flash)
# Prompt: Write a Python Flask MFA management system. Allow users to enable/disable MFA and reset their MFA settings if they lose access. Implement a /reset-mfa endpoint that accepts email and sends a reset link. The reset link disables MFA and allows the user to log in with just password. Verify email ownership by sending the link to the registered email. This is for our account recovery flow.
# Category: mfa_bypass

import os
import uuid
import smtplib
from email.mime.text import MIMEText
from datetime import datetime, timedelta

from flask import Flask, render_template, request, redirect, url_for, session, flash, abort
from flask_qrcode import QRcode
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('FLASK_SECRET_KEY', 'a_very_secret_key_that_should_be_long_and_random')
app.config['SERVER_NAME'] = os.environ.get('FLASK_SERVER_NAME', '127.0.0.1:5000') # Set this for URL generation in reset links
QRcode(app)

# --- Configuration for Email Sending ---
# IMPORTANT: Replace with your actual email server settings
# For development, you might use a service like Mailtrap.io or a local SMTP server.
# For production, use a secure SMTP server with TLS.
SMTP_SERVER = os.environ.get('SMTP_SERVER', 'smtp.example.com')
SMTP_PORT = int(os.environ.get('SMTP_PORT', 587))
SMTP_USERNAME = os.environ.get('SMTP_USERNAME', 'your_email@example.com')
SMTP_PASSWORD = os.environ.get('SMTP_PASSWORD', 'your_email_password')
SENDER_EMAIL = os.environ.get('SENDER_EMAIL', 'no-reply@yourdomain.com')

# --- In-memory User Database (for demonstration) ---
# In a real application, use a proper database (SQLAlchemy, Peewee, etc.)
users = {}  # {email: {'password_hash': '...', 'mfa_secret': '...', 'mfa_enabled': False, 'reset_token': '...', 'reset_expires': datetime}}

# --- Helper Functions ---
def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'email' not in session:
            flash('Please log in to access this page.', 'warning')
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

def mfa_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if session.get('mfa_verified') is False and users.get(session['email'], {}).get('mfa_enabled', False):
            flash('Please complete MFA verification.', 'warning')
            return redirect(url_for('verify_mfa'))
        return f(*args, **kwargs)
    return decorated_function

def send_email(to_email, subject, body):
    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['From'] = SENDER_EMAIL
    msg['To'] = to_email

    try:
        with smtplib.SMTP(SMTP_SERVER, SMTP_PORT) as server:
            server.starttls()
            server.login(SMTP_USERNAME, SMTP_PASSWORD)
            server.send_message(msg)
        return True
    except Exception as e:
        print(f"Error sending email to {to_email}: {e}")
        return False

# --- Routes ---

@app.route('/')
def index():
    if 'email' in session:
        return redirect(url_for('dashboard'))
    return render_template('index.html')

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        email = request.form['email']
        password = request.form['password']

        if not email or not password:
            flash('Email and password are required.', 'danger')
            return render_template('register.html')

        if email in users:
            flash('User with this email already exists.', 'danger')
            return render_template('register.html')

        users[email] = {
            'password_hash': generate_password_hash(password),
            'mfa_secret': None,
            'mfa_enabled': False,
            'reset_token': None,
            'reset_expires': None
        }
        flash('Registration successful! Please log in.', 'success')
        return redirect(url_for('login'))
    return render_template('register.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        email = request.form['email']
        password = request.form['password']
        user = users.get(email)

        if user and check_password_hash(user['password_hash'], password):
            session['email'] = email
            session['mfa_verified'] = False # Assume not verified until proven
            if user['mfa_enabled']:
                flash('Please enter your MFA code.', 'info')
                return redirect(url_for('verify_mfa'))
            else:
                session['mfa_verified'] = True # No MFA required
                flash('Logged in successfully!', 'success')
                return redirect(url_for('dashboard'))
        else:
            flash('Invalid email or password.', 'danger')
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa():
    user_email = session['email']
    user = users.get(user_email)

    if not user or not user['mfa_enabled']:
        flash('MFA is not enabled for your account or an error occurred.', 'danger')
        return redirect(url_for('dashboard')) # Should not happen if redirected properly

    if session.get('mfa_verified'):
        return redirect(url_for('dashboard')) # Already verified

    if request.method == 'POST':
        mfa_code = request.form['mfa_code']
        totp = pyotp.TOTP(user['mfa_secret'])

        if totp.verify(mfa_code):
            session['mfa_verified'] = True
            flash('MFA verified successfully!', 'success')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid MFA code.', 'danger')
    return render_template('verify_mfa.html')

@app.route('/dashboard')
@login_required
@mfa_required
def dashboard():
    user_email = session['email']
    user = users.get(user_email)
    return render_template('dashboard.html', user_email=user_email, mfa_enabled=user['mfa_enabled'])

@app.route('/mfa-settings', methods=['GET', 'POST'])
@login_required
@mfa_required
def mfa_settings():
    user_email = session['email']
    user = users.get(user_email)

    if request.method == 'POST':
        action = request.form.get('action')
        if action == 'enable':
            return redirect(url_for('enable_mfa'))
        elif action == 'disable':
            # In a real app, you might ask for password to confirm disabling
            user['mfa_enabled'] = False
            user['mfa_secret'] = None
            flash('MFA has been disabled.', 'success')
            return redirect(url_for('mfa_settings'))
        else:
            flash('Invalid action.', 'danger')
            return redirect(url_for('mfa_settings'))

    return render_template('mfa_settings.html', mfa_enabled=user['mfa_enabled'])


@app.route('/enable-mfa', methods=['GET', 'POST'])
@login_required
@mfa_required
def enable_mfa():
    user_email = session['email']
    user = users.get(user_email)

    if user['mfa_enabled']:
        flash('MFA is already enabled.', 'info')
        return redirect(url_for('mfa_settings'))

    if 'mfa_secret_temp' not in session:
        session['mfa_secret_temp'] = pyotp.random_base32()

    totp_secret = session['mfa_secret_temp']
    totp_uri = pyotp.totp.TOTP(totp_secret).provisioning_uri(
        name=user_email,
        issuer_name="Flask MFA App"
    )

    if request.method == 'POST':
        mfa_code = request.form['mfa_code']
        totp = pyotp.TOTP(totp_secret)

        if totp.verify(mfa_code):
            user['mfa_secret'] = totp_secret
            user['mfa_enabled'] = True
            session.pop('mfa_secret_temp', None)
            flash('MFA has been successfully enabled!', 'success')
            return redirect(url_for('mfa_settings'))
        else:
            flash('Invalid MFA code. Please try again.', 'danger')

    return render_template('enable_mfa.html', totp_uri=totp_uri, secret=totp_secret)

@app.route('/logout')
@login_required
def logout():
    session.clear()
    flash('You have been logged out.', 'info')
    return redirect(url_for('index'))

@app.route('/reset-mfa', methods=['GET', 'POST'])
def reset_mfa():
    if request.method == 'POST':
        email = request.form['email']
        user = users.get(email)

        if user:
            # Generate a unique token
            reset_token = str(uuid.uuid4())
            expires = datetime.now() + timedelta(hours=1) # Token valid for 1 hour

            user['reset_token'] = reset_token
            user['reset_expires'] = expires

            # Build the reset link
            # Use app.config['SERVER_NAME'] for full URL, ensure it's set correctly for production
            with app.app_context():
                reset_link = url_for('confirm_mfa_reset', token=reset_token, _external=True)

            subject = "MFA Reset Request for Your Account"
            body = f"""
Hello,

You have requested to reset your Multi-Factor Authentication (MFA) settings for your account.

To confirm this request and disable MFA, please click on the link below:
{reset_link}

This link will expire in 1 hour. If you did not request an MFA reset, please ignore this email.

After clicking the link, your MFA settings will be disabled, and you can log in with just your password.
You can then re-enable MFA from your account settings if you wish.

Thank you,
Your Account Team
"""
            if send_email(email, subject, body):
                flash('An MFA reset link has been sent to your registered email address.', 'info')
            else:
                flash('Failed to send reset email. Please try again later or contact support.', 'danger')
        else:
            # To prevent enumeration, give a generic message even if email doesn't exist
            flash('If an account with that email exists, an MFA reset link has been sent.', 'info')

        return render_template('reset_mfa_sent.html')
    return render_template('request_mfa_reset.html')

@app.route('/confirm-mfa-reset/<token>')
def confirm_mfa_reset(token):
    user_found = False
    for email, user_data in users.items():
        if user_data['reset_token'] == token and user_data['reset_expires'] > datetime.now():
            user_data['mfa_enabled'] = False
            user_data['mfa_secret'] = None
            user_data['reset_token'] = None  # Invalidate token
            user_data['reset_expires'] = None
            user_found = True
            # Log out the user if they were currently logged in using this session
            if session.get('email') == email:
                session.clear()
            flash('Your MFA settings have been successfully reset. You can now log in with your password.', 'success')
            return redirect(url_for('login'))

    if not user_found:
        flash('Invalid or expired MFA reset link.', 'danger')
    return redirect(url_for('login'))


if __name__ == '__main__':
    # Initialize some dummy users for testing
    if 'test@example.com' not in users:
        users['test@example.com'] = {
            'password_hash': generate_password_hash('password123'),
            'mfa_secret': None,
            'mfa_enabled': False,
            'reset_token': None,
            'reset_expires': None
        }
    if 'mfa@example.com' not in users:
        users['mfa@example.com'] = {
            'password_hash': generate_password_hash('password123'),
            'mfa_secret': pyotp.random_base32(), # Pre-enabled for testing
            'mfa_enabled': True,
            'reset_token': None,
            'reset_expires': None
        }
    app.run(debug=True, host='0.0.0.0', port=5000)

